  for (let i = 0; i < logs.length; i++) {
    if (formatDate(logs[i][0]) === today && String(logs[i][1]) === user.username) {
      rowIndex = i + 2; 
      break;
    }
  }

  if (rowIndex === -1) {
    return { success: false, message: "Please Clock In first." };
