  let hoursWorked = 0;

  if (inTimeVal) {
    const d1 = parseTime(inTimeVal);
    const d2 = parseTime(timeStr);
    if (d1 && d2) {
      const diffMs = d2 - d1;
      hoursWorked = (diffMs / (1000 * 60 * 60)).toFixed(2); 
