  const handleLogout = () => {
    setUser(null);
    // Keep the username filled if LINE ID is present
    if (lineUserId) {
        setUsernameInput(lineUserId);
    } else {
        setUsernameInput("");
    }
    setPasswordInput("");
    setSuccess(null);
    setError(null);
    setIsProfileOpen(false);
